import { Alert, AlertAction, AlertDescription, AlertTitle, Button } from "@shery-ui/components";
import { AlertTriangle } from "lucide-react";

export default function AlertDestructive() {
  return (
    <Alert variant="destructive">
      <AlertTriangle className="h-4 w-4" />
      <AlertTitle>Delete failed</AlertTitle>
      <AlertDescription>
        We couldn't delete your project due to a server error. Please try again.
      </AlertDescription>
      <AlertAction>
        <Button size="xs" variant="outline">Retry</Button>
      </AlertAction>
    </Alert>
  );
}
